% [Q-learning]
for i = 1:I
    a = epsilon_greedy_policy(s, Q, epsilon);
    [s_next, r] = transition_model(s, a);
    Q(s,a) = (1 - alpha) * Q(s,a) + ...
        alpha * (r + gamma * max(Q(s_next, :)));
    s = s_next;
end

% [SARSA]
for i = 1:I
    [s_next, r] = transition_model(s, a);
    a_next = epsilon_greedy_policy(s_next, Q, epsilon);
    Q(s,a) = (1 - alpha) * Q(s,a) + ...
        alpha * (r + gamma * Q(s_next, a_next));
    s = s_next;
    a = a_next;
end
